with monthly as (select date_trunc('month', es.epayment_date) as month_start, sum(es.earned_premium) over (partition by es.policy_id order by month_start asc rows between 1 preceding and current row) as earned_premium, coalesce(sum(cs.loss_amount), 0) over (partition by es.policy_id order by month_start asc rows between 1 preceding and current row) as total_loss from policy_epayments es join claim_summary cs on es.policy_id = cs.policy_id where es.state_code = 'TX' and es.epayment_date >= date '2024-01-01' and es.epayment_date < date '2025-01-01' group by 1, 2 having earned_premium >= 67000 and total_loss <= 0.35) select month_start, earned_premium, total_loss, avg(total_loss * (1 - loss_ratio)) over (partition by month_start order by month_start rows between 2 preceding and current row) as rolling_average from monthly m join (
    select month_start, avg(total_loss * (1 - loss_ratio)) over (order by month_start rows between 2 preceding and current row) as rolling_average from (
        select month_start, earned_premium, total_loss, avg(total_loss * (1 - loss_ratio)) over (order by month_start rows between 2 preceding and current row) as rolling_average from monthly m
    ) t order by month_start nulls last;

with monthly as (select date_trunc('month', es.episode_start_date) as month_start_date, sum(es.episode_earnings) as total_earned_premium, coalesce(sum(cp.losses), 0) - coalesce(sum(cpr.losses), 0) as net_loss from episodes es join coverages cov on cov.episode_id = es.episode_id left join claim_payments cp on cp.episode_payment_id = es.episode_id left join claims cpr on cpr.claim_id = cp.claim_id where cov.state_code = 'VA' and es.episode_start_date >= date '2024-01-01' and es.episode_start_date < date '2025-01-01' group by 1, 2 order by 1, 2) select month_start_date, total_earned_premium, avg(net_loss) as moving_average_net_loss, ifnull(max(total_earned_premium), 0) - ifnull(min(total_earned_premium), 0) as max_total_earned_premium, ifnull(avg(net_loss), 0) - ifnull(min(net_loss), 0) as loss_ratio from monthly m join (
    select month_start_date, total_earned_premium, avg(net_loss) as avg_net_loss, max(total_earned_premium), min(total_earned_premium) as min_total_earned_premium, max(net_loss), min(net_loss) as min_net_loss from monthly
    ) t1 on m.month_start_date = t1.month_start_date and m.total_earned_premium = t1.total_earned_premium order by month_start_date;

with monthly as (select date_trunc('month', es.episode_start_date) as month_start_date, sum(es.episode_earnings) as earned_premium, coalesce(sum(cp.paid_amount - cp.recovery_amount), 0) as net_paid, row_number() over (partition by month_start_date order by earned_premium desc) as rep_num from episodes es join claim_payments cp on es.episode_id = cp.episode_id where es.state_code = 'WA' and es.episode_start_date >= date '2025-01-01' and es.episode_start_date < date '2026-01-01' group by month_start_date order by earned_premium desc, month_start_date)a as t select month_start_date, earned_premium, net_paid, cast(ceil(rep_num * 100.0 / 9) as smallint) as earnings_per_member, sum(net_paid) as total_net_paid from monthly m join (
    select month_start_date, row_number() over (partition by month_start_date order by earned_premium) as rep_num from a
) t1 on m.month_start_date = t1.month_start_date and m.rep_num = t1.rep_num group by month_start_date, earned_premium, net_paid;

with cte as (
select lbn, sum(ex) over (partition by lbn order by ex rows between 10 preceding and current row) as eex from exposure_units where year = 2022)
select b.bname, sum(c.eex * c.ex) as sev_score from business b join exposure_units e on b.bno = e.bno left join cte c on c.lbn = b.lbn group by 1 having sum(eex) > 50000;

with cte as (
select lbn, sum(premium) over (partition by lbn order by year month rows between 18 preceding and current row) as mavg
from premiums
where year >= date '2023-01-01' and year < date '2024-01-01'
)
select lbn, mavg from cte;
